"use client";
import * as React from "react";
import { sliderAnatomy } from "@tessera/core";
import { useControllableState } from "../utils/hooks";

export interface SliderProps {
  label: string;
  value?: number;
  defaultValue?: number;
  onValueChange?: (value: number) => void;
  min?: number;
  max?: number;
  step?: number;
  disabled?: boolean;
  /** Show the current value beside the label. Default true. */
  showValueText?: boolean;
  /** Format the displayed value, e.g. (v) => `${v}%`. */
  formatValue?: (value: number) => string;
}

/** Built on a native range input: keyboard, touch, and a11y come from the browser. */
export const Slider = React.forwardRef<HTMLInputElement, SliderProps>(function Slider(
  {
    label,
    value,
    defaultValue,
    onValueChange,
    min = 0,
    max = 100,
    step = 1,
    disabled,
    showValueText = true,
    formatValue = String,
  },
  ref
) {
  const [current, setValue] = useControllableState({
    value,
    defaultValue: defaultValue ?? min,
    onChange: onValueChange,
  });
  const id = React.useId();
  const percent = ((current - min) / (max - min)) * 100;

  return (
    <div {...sliderAnatomy.attrs("root")}>
      <label {...sliderAnatomy.attrs("label")} htmlFor={id}>
        <span>{label}</span>
        {showValueText && (
          <span {...sliderAnatomy.attrs("valueText")}>{formatValue(current)}</span>
        )}
      </label>
      <input
        type="range"
        {...sliderAnatomy.attrs("control")}
        id={id}
        ref={ref}
        min={min}
        max={max}
        step={step}
        value={current}
        disabled={disabled}
        onChange={(event) => setValue(Number(event.target.value))}
        style={{ "--slider-progress": `${percent}%` } as React.CSSProperties}
      />
    </div>
  );
});

@layer tessera.recipes {
  [data-scope="slider"][data-part="root"] {
    display: flex;
    flex-direction: column;
    gap: var(--ts-space-1);
    width: 100%;
    max-width: 20rem;
  }

  [data-scope="slider"][data-part="label"] {
    display: flex;
    justify-content: space-between;
    font-size: var(--ts-font-size-sm);
    font-weight: var(--ts-font-weight-medium);
    color: var(--ts-fg-default);
  }

  [data-scope="slider"][data-part="valueText"] {
    color: var(--ts-fg-muted);
    font-weight: var(--ts-font-weight-regular);
    font-variant-numeric: tabular-nums;
  }

  [data-scope="slider"][data-part="control"] {
    appearance: none;
    width: 100%;
    height: 1.25rem;
    background: transparent;
    cursor: pointer;
    margin: 0;
  }

  [data-scope="slider"][data-part="control"]::-webkit-slider-runnable-track {
    height: 0.375rem;
    border-radius: var(--ts-radius-full);
    background: linear-gradient(
      to right,
      var(--ts-accent-default) var(--slider-progress, 0%),
      var(--ts-bg-muted) var(--slider-progress, 0%)
    );
  }

  [data-scope="slider"][data-part="control"]::-webkit-slider-thumb {
    appearance: none;
    width: 1.125rem;
    height: 1.125rem;
    margin-top: -0.375rem;
    border-radius: var(--ts-radius-full);
    border: 2px solid var(--ts-accent-default);
    background: var(--ts-bg-canvas);
    box-shadow: var(--ts-shadow-sm);
  }

  [data-scope="slider"][data-part="control"]::-moz-range-track {
    height: 0.375rem;
    border-radius: var(--ts-radius-full);
    background: var(--ts-bg-muted);
  }

  [data-scope="slider"][data-part="control"]::-moz-range-progress {
    height: 0.375rem;
    border-radius: var(--ts-radius-full);
    background: var(--ts-accent-default);
  }

  [data-scope="slider"][data-part="control"]::-moz-range-thumb {
    width: 1.125rem;
    height: 1.125rem;
    border-radius: var(--ts-radius-full);
    border: 2px solid var(--ts-accent-default);
    background: var(--ts-bg-canvas);
    box-shadow: var(--ts-shadow-sm);
  }

  [data-scope="slider"][data-part="control"]:focus-visible {
    outline: 2px solid var(--ts-ring-color);
    outline-offset: 4px;
    border-radius: var(--ts-radius-full);
  }
}
